import express, { Request, Response } from 'express';
import { getRepository } from 'typeorm';
import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn } from 'typeorm';

@Entity('products')
class Product {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  name: string;

  @Column('text')
  description: string;

  @Column('decimal', { precision: 10, scale: 2 })
  price: number;

  @Column()
  category: string;

  @Column()
  brand: string;

  @Column('int')
  stock: number;

  @Column({ default: true })
  isActive: boolean;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}

const app = express();
app.use(express.json());

app.get('/api/products/search', async (req: Request, res: Response) => {
  try {
    const { 
      name, 
      category, 
      brand, 
      minPrice, 
      maxPrice, 
      inStock, 
      sortBy, 
      sortOrder,
      limit,
      offset 
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT * FROM products WHERE 1=1`;

    if (name) {
      query += ` AND name LIKE '%${name}%'`;
    }

    if (category) {
      query += ` AND category = '${category}'`;
    }

    if (brand) {
      query += ` AND brand = '${brand}'`;
    }

    if (minPrice) {
      query += ` AND price >= ${minPrice}`;
    }

    if (maxPrice) {
      query += ` AND price <= ${maxPrice}`;
    }

    if (inStock === 'true') {
      query += ` AND stock > 0`;
    }

    if (sortBy) {
      const order = sortOrder === 'desc' ? 'DESC' : 'ASC';
      query += ` ORDER BY ${sortBy} ${order}`;
    }

    if (limit) {
      query += ` LIMIT ${limit}`;
    }

    if (offset) {
      query += ` OFFSET ${offset}`;
    }

    const products = await productRepository.query(query);

    res.json({
      success: true,
      count: products.length,
      data: products
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Error searching products',
      error: error.message
    });
  }
});

app.get('/api/products/advanced-search', async (req: Request, res: Response) => {
  try {
    const { 
      search,
      categories,
      brands,
      priceRange,
      rating,
      tags
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT p.* FROM products p WHERE p.isActive = true`;

    if (search) {
      query += ` AND (p.name LIKE '%${search}%' OR p.description LIKE '%${search}%')`;
    }

    if (categories) {
      const categoryList = (categories as string).split(',').map(c => `'${c}'`).join(',');
      query += ` AND p.category IN (${categoryList})`;
    }

    if (brands) {
      const brandList = (brands as string).split(',').map(b => `'${b}'`).join(',');
      query += ` AND p.brand IN (${brandList})`;
    }

    if (priceRange) {
      const [min, max] = (priceRange as string).split('-');
      query += ` AND p.price BETWEEN ${min} AND ${max}`;
    }

    if (rating) {
      query += ` AND p.id IN (SELECT product_id FROM reviews WHERE rating >= ${rating})`;
    }

    if (tags) {
      const tagList = (tags as string).split(',');
      tagList.forEach(tag => {
        query += ` AND EXISTS (SELECT 1 FROM product_tags pt WHERE pt.product_id = p.id AND pt.tag = '${tag}')`;
      });
    }

    const products = await productRepository.query(query);

    res.json({
      success: true,
      results: products
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

